createEffect(() => {
  const canvas = glueScrollBarCanvasRef;
  const bgUrl = glueScrollBgUrl();
  const borderUrl = glueScrollBorderUrl();
  if (!canvas || !bgUrl || !borderUrl) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrl),
    loadDataUrlImage(borderUrl),
  ])
    .then(([bgImg, borderImg]) => {
      if (cancelled) return;
      const w = canvas.clientWidth || 1;
      drawTemplateNineSliceToCanvas(canvas, bgImg, borderImg, {
        cornerPx: w * glueScrollCornerRatio,
        insetPx: w * glueScrollInsetRatio,
        tileBackground: true,
        opaqueBaseFill: '#000',
      });
    })
    .catch((err) => console.error(err));

  onCleanup(() => {
    cancelled = true;
  });
});

